#include <iostream>

class Point {
public:
    int x;
    int y;

    Point(int x_coord = 0, int y_coord = 0) : x(x_coord), y(y_coord) {}

    Point& operator++() {
        ++x;
        ++y;
        return *this;
    }

    void print() const {
        std::cout << "(" << x << ", " << y << ")";
    }
};

int main() {
    Point p1(10, 20);
    std::cout << "Original point p1: ";
    p1.print();
    std::cout << std::endl;

    ++p1;
    std::cout << "After ++p1: ";
    p1.print();
    std::cout << std::endl;

    Point p2(0, 0);
    std::cout << "Original point p2: ";
    p2.print();
    std::cout << std::endl;

    Point& p_ref = ++(++p2);
    std::cout << "After ++(++p2): ";
    p_ref.print();
    std::cout << std::endl;

    p_ref.x = 100;
    std::cout << "After p_ref.x = 100: ";
    p2.print();
    std::cout << std::endl;

    return 0;
}
